VALUES
  ('social-worker-moex-06920', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '逐漸普遍受到歡迎的調查方式是透過網路的線上調查法（online surveys），下列那一項不是它的優點？', '["便宜省時", "有代表性", "樣本相當大", "有匿名性"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06921', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '透過電話進行的調查，最近幾年已變得更為常見及有效，而電腦輔助電話訪問（CATI）的技巧更是便利， 請問下列那一項敘述正確？', '["沒有登記電話號碼的人或家庭，可以用隨機數字撥號方式改善這個問題", "無法釐清疑惑問題", "不方便統計分析", "樣本選擇不容易"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06922', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '快樂社區理事長想訪問社區耆老，建立社區歷史資料，社工師建議可以採用生命史（life history）研究方 法，請問下列那一項敘述正確？', '["有客觀的精確性", "是一種質性訪談的方法", "以封閉式問題比較容易發掘生活中的重大事件", "對生活事件的意義及影響較無法理解"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "1d0f7c4c7766", "answer_pdf_sha1": "06556a0af8b4", "source_family": "moex-gov-tw", "moex": {"exam_code": "102030", "c": "111", "s": "0706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第一次專技醫師中醫師分試中醫師營養師心理師醫事檢驗師護理師社會工作師、特考聽力牙體語言治療師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06923', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '進行推論檢定時，如果有不只一種方法適用，原則上應優先選擇：', '["考驗力大的檢定", "顯著性高的檢定", "自由度大的檢定", "強韌性大的檢定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06924', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某人想知道夫妻情緒智商（EQ）是否相似，他隨機選取12對夫妻測量其EQ分數，並進行平均數t考驗。 結果，夫、妻EQ平均數分別是29.33、35.67，樣本相關係數 .037，p=.909，t值(-1.998)，p=.071。下列敘 述，何者正確？', '["它採用的是單一樣本t檢定", "t值考驗結果達到顯著性，夫妻情緒智商有顯著差異", "t值考驗結果沒有達到顯著性，夫妻情緒智商沒有顯著差異", "它需要再進行多元共線性（multicollinearnality）分析"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06925', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列對研究設計中「分析單位（unit of analysis）」的敘述，何者正確？', '["幫派整體特質比較性研究的分析單位是「個人」", "報紙社論中自由主義傾向比較性研究的分析單位是「個別的社論」", "社會科學的分析單位禁止包含諸如繪畫在內的「社會人造事實（social artifact）」", "把團體作為分析單位的結論概推到團體中的個人身上，稱為「個體的謬誤（individualistic fallacy）」"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06926', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列有關「按數量成比例的機率抽樣（ Probability Proportionate to Size Sampling，簡稱PPS）」敘述，何 者正確？', '["它是種透過獎勵機制來提高樣本數，並且擴充代表性的一種抽樣方法", "它是種讓母群體中含量大的部分被抽中的機率也大，可以提高樣本代表性方法", "它適用於不容易取得完整的母體名冊，缺乏相關輔助變項的研究之中", "為了要降低樣本蒐集成本及抽樣誤差，這種方法對輔助變項資訊的要求程度低"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06927', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '某研究者從選取用以形成所探究概念的類似樣本著手，但是當他發現再也無法產生新的見地之後，就換 另個類型的樣本繼續研究。這種抽樣方法是：', '["機率抽樣（probability sampling）", "限額抽樣（quota sampling ）", "理論抽樣（theoretical sampling）", "滾雪球抽樣（snowball sampling）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06928', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列對福利服務滿意度中測量誤差的敘述，何者正確？', '["受訪者故意用低服務滿意度分數，破壞福利機構良好形象，稱為社會期望的偏誤（social desirability bias）", "受訪者隨著時間和服務的改變，回答出不同的滿意度分數，稱為隨機性的誤差（random error）", "受訪者滿意所提供的福利服務，卻給了低滿意度分數，稱為月暈效應（halo effect）", "受訪者填寫服務滿意度問卷時，無論正負向題都答非常滿意，稱為順勢反應（acquiescent response set）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-06929', 'social-worker', 'social-worker-moex-102-a62ebd66', 'sub-social-worker-04', NULL, 'single_choice', '下列因素中，那一個不會影響抽樣誤差的大小？', '["母群體大小", "樣本大小", "信心水準高低", "標準誤大小"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:36+00:00", "source_pdf_sha1": "99363aa390a6", "answer_pdf_sha1": "dce05175af2d", "source_family": "moex-gov-tw", "moex": {"exam_code": "102110", "c": "110", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作研究方法", "year": "102", "exam_name": "102年第二次專技醫師中醫師分試中醫師營養師心理師護理師社會工作師、特考聽力牙體技術人員、法醫師語言聽力牙體技術師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
